import ldap

def search_user_by_username(username, ldap_server, ldap_port, ldap_base_dn):
    """
    Searches for a user in an LDAP directory by their username.

    Args:
        username: The username to search for.
        ldap_server: The LDAP server address.
        ldap_port: The LDAP server port.
        ldap_base_dn: The base distinguished name for the LDAP directory.

    Returns:
        A dictionary containing the user information, or None if the user is not found.
    """

    # Connect to the LDAP server
    ldap_connection = ldap.initialize(f"ldap://{ldap_server}:{ldap_port}")

    # Set the search filter
    search_filter = f"uid={username}"

    # Search for the user
    ldap_result = ldap_connection.search(ldap_base_dn, ldap.SCOPE_SUBTREE, search_filter)

    # Check if the user was found
    if not ldap_result:
        return None

    # Get the user information
    user_info = ldap_result[0][1]

    # Close the LDAP connection
    ldap_connection.unbind()

    # Return the user information
    return user_info